sql:
SELECT enzyme_name
FROM enzymes
WHERE functional_class = 'CBM12';

SELECT food_name, food_description
FROM foods
WHERE food_id = 1;

SELECT pair_name
FROM enzymeBinPairsFoods
WHERE bin_id = 1;

SELECT enzyme_name, functional_class
FROM enzymes
WHERE enzyme_id = 1;

SELECT fec.food_id, fec.enzyme_id
FROM food_enzyme_correlations AS fec
WHERE fec.analysis_date = '2022-01-01';

SELECT enzyme_name
FROM enzymes
WHERE enzyme_id = (SELECT MAX(enzyme_id) FROM enzymes);

SELECT COUNT(*) AS enzyme_count
FROM enzymes
WHERE functional_class = 'CBM';

SELECT food_id
FROM food_enzyme_correlations
WHERE coef = (SELECT MAX(coef) FROM food_enzyme_correlations);

SELECT pair_name
FROM binFoodPairs
WHERE bin_id = 1;

SELECT enzyme_name
FROM enzymes
WHERE created_at = (SELECT MIN(created_at) FROM enzymes);

SELECT enzyme_name
FROM enzymes
ORDER BY enzyme_name ASC;

SELECT bin_name
FROM bins
WHERE bin_id = 0;

SELECT analysis_id, MAX(result_value) AS max_result_value
FROM analysisResults
WHERE analysis_id = 1;

SELECT triple_name
FROM enzymeFunctionalClassTriples
WHERE bin_id = 1;
